import React, {
  useRef,
  useState,
  useCallback,
  useImperativeHandle,
} from "react";
import { cn, cva } from "../../lib/utils";
import type { CardHeaderProps, CardHeaderRef } from "../../types/card";
import { CardHeaderStatus } from "../../types/card";

/**
 * Status color variants for additional text
 */
const statusVariants = cva("text-sm", {
  variants: {
    status: {
      [CardHeaderStatus.None]: "text-sapphire-text-tertiary",
      [CardHeaderStatus.Positive]: "text-sapphire-positive",
      [CardHeaderStatus.Negative]: "text-sapphire-negative",
      [CardHeaderStatus.Critical]: "text-sapphire-warning",
      [CardHeaderStatus.Information]: "text-sapphire-info",
    },
  },
  defaultVariants: {
    status: CardHeaderStatus.None,
  },
});

/**
 * CardHeader component
 *
 * A header component for Card with title, subtitle, additional text,
 * avatar, and action slots. Supports interactive mode with keyboard
 * navigation and click events.
 *
 * ACCESSIBILITY:
 * When interactive, the content area (avatar + title + subtitle) becomes
 * a role="button" element. The action slot is always rendered separately
 * to prevent nested interactive elements, which would be flattened in the
 * accessibility tree (ARIA "Presentational Children" concept).
 *
 * @example
 * ```tsx
 * // Basic header
 * <CardHeader
 *   titleText="Card Title"
 *   subtitleText="Subtitle"
 * />
 *
 * // Interactive header with avatar and action
 * <CardHeader
 *   titleText="John Doe"
 *   subtitleText="Developer"
 *   additionalText="Online"
 *   status="Positive"
 *   interactive
 *   avatar={<Avatar initials="JD" />}
 *   action={<Button icon={<MoreVertical />} iconOnly />}
 *   onClick={() => console.log('Header clicked')}
 * />
 * ```
 */
export const CardHeader = React.forwardRef<CardHeaderRef, CardHeaderProps>(
  (
    {
      titleText,
      subtitleText,
      additionalText,
      interactive = false,
      avatar,
      action,
      status = CardHeaderStatus.None,
      ariaLevel = 3,
      accessibleName,
      accessibleNameRef,
      accessibleDescriptionRef,
      onClick,
      className,
      style,
      id,
      "data-testid": dataTestId,
    },
    ref
  ) => {
    const headerRef = useRef<HTMLDivElement>(null);
    const interactiveRef = useRef<HTMLDivElement>(null);
    const [isPressed, setIsPressed] = useState(false);

    // Expose imperative methods
    useImperativeHandle(
      ref,
      () => {
        const target = interactive ? interactiveRef.current : headerRef.current;
        return {
          focus() {
            target?.focus();
          },
          blur() {
            target?.blur();
          },
          isFocused() {
            if (interactive) {
              return (
                document.activeElement === interactiveRef.current ||
                headerRef.current?.contains(document.activeElement) === true
              );
            }
            return document.activeElement === headerRef.current;
          },
          get nativeElement() {
            return headerRef.current;
          },
        };
      },
      [interactive]
    );

    // Click handler
    const handleClick = useCallback(
      (e: React.MouseEvent<HTMLDivElement>) => {
        if (!interactive) return;
        onClick?.({ originalEvent: e, isKeyboard: false });
      },
      [interactive, onClick]
    );

    // Keyboard handler
    const handleKeyDown = useCallback(
      (e: React.KeyboardEvent<HTMLDivElement>) => {
        if (!interactive) return;
        if (e.key === "Enter" || e.key === " ") {
          e.preventDefault();
          setIsPressed(true);
          onClick?.({ originalEvent: e, isKeyboard: true });
        }
      },
      [interactive, onClick]
    );

    const handleKeyUp = useCallback((e: React.KeyboardEvent<HTMLDivElement>) => {
      if (e.key === "Enter" || e.key === " ") {
        setIsPressed(false);
      }
    }, []);

    // Render title content
    // suppressHeading: true when title is inside an interactive element (role="button")
    const renderTitle = (suppressHeading: boolean) => {
      if (!titleText) return null;
      return (
        <div
          role={suppressHeading ? undefined : "heading"}
          aria-level={suppressHeading ? undefined : ariaLevel}
          className="text-base font-semibold text-sapphire-text-primary leading-[22px] line-clamp-3 flex-1 min-w-0"
          data-part="title"
        >
          {titleText}
        </div>
      );
    };

    // Render content area (title, subtitle, additionalText)
    const renderContent = () => (
      <div className="flex-1 min-w-0">
        {(titleText || additionalText) && (
          <div className="flex items-center gap-2">
            {renderTitle(interactive)}
            {additionalText && (
              <span
                className={cn("flex-shrink-0", statusVariants({ status: status as CardHeaderStatus }))}
                data-part="additional-text"
              >
                {additionalText}
              </span>
            )}
          </div>
        )}
        {subtitleText && (
          <p className="text-sm leading-5 text-sapphire-text-secondary line-clamp-2 mt-1" data-part="subtitle">
            {subtitleText}
          </p>
        )}
      </div>
    );

    // Unified structure - works for both interactive and non-interactive cases
    return (
      <div
        ref={headerRef}
        id={id}
        className={cn(
          "flex items-center gap-4 p-4 border-b border-sapphire-border-primary rounded-t-[8px]",
          interactive && [
            "hover:bg-sapphire-background-secondary/50 transition-colors",
            isPressed && "bg-sapphire-background-secondary/70",
            // No focus ring on header when interactive - focus shows on card border
          ],
          className
        )}
        style={style}
        data-testid={dataTestId}
        data-part="root"
      >
        {/* Content area - becomes interactive when interactive=true */}
        <div
          ref={interactive ? interactiveRef : undefined}
          role={interactive ? "button" : undefined}
          tabIndex={interactive ? 0 : undefined}
          aria-roledescription={interactive ? "Interactive Card Header" : undefined}
          aria-label={accessibleName}
          aria-labelledby={accessibleNameRef}
          aria-describedby={accessibleDescriptionRef}
          onClick={interactive ? handleClick : undefined}
          onKeyDown={interactive ? handleKeyDown : undefined}
          onKeyUp={interactive ? handleKeyUp : undefined}
          onMouseDown={interactive ? () => setIsPressed(true) : undefined}
          onMouseUp={interactive ? () => setIsPressed(false) : undefined}
          onMouseLeave={interactive && isPressed ? () => setIsPressed(false) : undefined}
          className={cn(
            "flex items-center gap-3 flex-1 min-w-0",
            interactive && "cursor-pointer focus:outline-none rounded-[4px]"
          )}
          data-part={interactive ? "interactive-area" : "content-area"}
        >
          {avatar && (
            <div className="flex-shrink-0" data-part="avatar">
              {avatar}
            </div>
          )}
          {renderContent()}
        </div>

        {/* Action slot - always separate when present */}
        {action && (
          <div
            className="flex-shrink-0 z-10"
            data-part="action"
          >
            {action}
          </div>
        )}
      </div>
    );
  }
);

CardHeader.displayName = "CardHeader";
